<template><el-card><template #header><div class="head"><b>我的申请</b><el-button v-if="user.hasPermission('application:create')" type="primary" @click="$router.push('/applications/create')">新建申请</el-button></div></template>
<el-form inline><el-form-item label="申请编号"><el-input v-model="query.applicationNo" clearable/></el-form-item><el-form-item label="状态"><el-select v-model="query.status" clearable style="width:150px"><el-option v-for="s in statuses" :key="s" :label="s" :value="s"/></el-select></el-form-item><el-button type="primary" @click="load">查询</el-button></el-form>
<el-table :data="rows" v-loading="loading"><el-table-column prop="applicationNo" label="申请编号" width="230"/><el-table-column prop="title" label="标题"/><el-table-column prop="businessType" label="业务类型" width="210"/><el-table-column prop="status" label="状态" width="130"/><el-table-column label="操作" width="100"><template #default="{row}"><el-button link type="primary" @click="$router.push(`/applications/${row.applicationId}`)">详情</el-button></template></el-table-column></el-table>
<el-pagination v-model:current-page="page" :page-size="10" :total="total" layout="prev,pager,next,total" @current-change="load"/></el-card></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{listApplications}from'../../api/applications';import{useUserStore}from'../../stores/user';const user=useUserStore(),rows=ref([]),total=ref(0),page=ref(1),loading=ref(false),query=reactive({applicationNo:'',status:''});const statuses=['DRAFT','UNDER_REVIEW','APPROVED','REJECTED','WITHDRAWN','CANCELLED'];async function load(){loading.value=true;try{const r=await listApplications({...query,page:page.value-1,size:10});rows.value=r.content||[];total.value=r.totalElements||0}finally{loading.value=false}}onMounted(load)</script>
<style scoped>.head{display:flex;justify-content:space-between;align-items:center}.el-pagination{margin-top:16px;justify-content:flex-end}</style>
